package com.lightevents.events;
import jakarta.persistence.*; import jakarta.validation.constraints.Email; import java.math.BigDecimal; import java.time.Instant; import java.util.UUID;
@Entity @Table(name="reservations")
public class Reservation { @Id @GeneratedValue(strategy=GenerationType.IDENTITY) private Long id; @Column(unique=true,nullable=false) private String reference=UUID.randomUUID().toString(); private Long eventId; private Long ticketTypeId; private String buyerName; @Email private String buyerEmail; private String buyerPhone; private String buyerWhatsapp; private boolean companyPurchase; private String companyName; private int quantity; private BigDecimal grossAmount=BigDecimal.ZERO; private BigDecimal platformFee=BigDecimal.ZERO; private BigDecimal organizerNet=BigDecimal.ZERO; @Enumerated(EnumType.STRING) private ReservationStatus status=ReservationStatus.HELD; private Instant expiresAt; private Instant createdAt=Instant.now(); public Long getId(){return id;} public String getReference(){return reference;} public Long getEventId(){return eventId;} public void setEventId(Long v){eventId=v;} public Long getTicketTypeId(){return ticketTypeId;} public void setTicketTypeId(Long v){ticketTypeId=v;} public String getBuyerName(){return buyerName;} public void setBuyerName(String v){buyerName=v;} public String getBuyerEmail(){return buyerEmail;} public void setBuyerEmail(String v){buyerEmail=v;} public String getBuyerPhone(){return buyerPhone;} public void setBuyerPhone(String v){buyerPhone=v;} public String getBuyerWhatsapp(){return buyerWhatsapp;} public void setBuyerWhatsapp(String v){buyerWhatsapp=v;} public boolean isCompanyPurchase(){return companyPurchase;} public void setCompanyPurchase(boolean v){companyPurchase=v;} public String getCompanyName(){return companyName;} public void setCompanyName(String v){companyName=v;} public int getQuantity(){return quantity;} public void setQuantity(int v){quantity=v;} public BigDecimal getGrossAmount(){return grossAmount;} public void setGrossAmount(BigDecimal v){grossAmount=v;} public BigDecimal getPlatformFee(){return platformFee;} public void setPlatformFee(BigDecimal v){platformFee=v;} public BigDecimal getOrganizerNet(){return organizerNet;} public void setOrganizerNet(BigDecimal v){organizerNet=v;} public ReservationStatus getStatus(){return status;} public void setStatus(ReservationStatus v){status=v;} public Instant getExpiresAt(){return expiresAt;} public void setExpiresAt(Instant v){expiresAt=v;} public Instant getCreatedAt(){return createdAt;} }
